import{_ as a,o as t,c as i,ae as o}from"./chunks/framework.CeoCFqMR.js";const y=JSON.parse('{"title":"Privacy policy","description":"Elena’s privacy policy and data practices.","frontmatter":{"title":"Privacy policy","description":"Elena’s privacy policy and data practices.","head":[["meta",{"property":"og:title","content":"Privacy policy | Elena"}],["meta",{"property":"og:description","content":"Elena’s privacy policy and data practices."}],["meta",{"name":"twitter:description","content":"Elena’s privacy policy and data practices."}]]},"headers":[{"level":2,"title":"Website analytics","slug":"website-analytics","link":"#website-analytics","children":[]},{"level":2,"title":"Search","slug":"search","link":"#search","children":[]},{"level":2,"title":"What this policy does not cover","slug":"what-this-policy-does-not-cover","link":"#what-this-policy-does-not-cover","children":[]},{"level":2,"title":"Contact","slug":"contact","link":"#contact","children":[]}],"relativePath":"about/privacy.md","filePath":"about/privacy.md","lastUpdated":1775369284000}'),r={name:"about/privacy.md"};function s(c,e,n,l,d,p){return t(),i("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /about/privacy.md for this page in Markdown format</div><h1 id="privacy-policy" tabindex="-1">Privacy policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy policy&quot;">​</a></h1><blockquote><p><strong>Effective date:</strong> March 19, 2026</p></blockquote><p>This privacy policy describes how we handle your information across our website (<a href="https://elenajs.com" target="_blank" rel="noreferrer">https://elenajs.com</a>), related documentation, and related services. Your privacy matters to us: we do not track individual visitors, use cookies, or collect personal information of any kind.</p><h2 id="website-analytics" tabindex="-1">Website analytics <a class="header-anchor" href="#website-analytics" aria-label="Permalink to &quot;Website analytics&quot;">​</a></h2><p>This website uses <a href="https://usefathom.com/" target="_blank" rel="noreferrer">Fathom Analytics</a> to collect anonymized visitor data. Fathom is a privacy-friendly analytics tool that does not use cookies and does not track visitors across sites.</p><p>When you visit this website, Fathom may briefly process your IP address to determine general location data, but this information is never stored in a way that can identify you. All visitor data is aggregated and anonymized. No personal information is collected, and visitors cannot be identified individually.</p><p>We use this data solely to understand website traffic and improve the documentation. The legal basis for this processing is legitimate interest (GDPR Article 6(1)(f)).</p><p>Fathom complies with GDPR, ePrivacy (PECR), COPPA, and CCPA. All data is stored and processed according to <a href="https://usefathom.com/legal/privacy" target="_blank" rel="noreferrer">Fathom’s privacy policy</a> and their data retention policies.</p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>The documentation search is powered by VitePress’s built-in search, which runs entirely in your browser. No search data is sent to external services.</p><h2 id="what-this-policy-does-not-cover" tabindex="-1">What this policy does not cover <a class="header-anchor" href="#what-this-policy-does-not-cover" aria-label="Permalink to &quot;What this policy does not cover&quot;">​</a></h2><p>This privacy policy does not cover:</p><ul><li>Open source code hosted on <a href="https://github.com/getelena/elena" target="_blank" rel="noreferrer">GitHub</a>, including interactions such as issues, pull requests, and discussions, which are governed by GitHub’s own <a href="https://docs.github.com/en/site-policy/privacy-policies/github-general-privacy-statement" target="_blank" rel="noreferrer">privacy policy</a>.</li><li>npm package download statistics, which are governed by npm’s <a href="https://docs.npmjs.com/policies/privacy" target="_blank" rel="noreferrer">privacy policy</a>.</li></ul><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>If you have questions about this privacy policy, you can reach us at <a href="mailto:hi@elenajs.com" target="_blank" rel="noreferrer">hi@elenajs.com</a>.</p>',16)])])}const u=a(r,[["render",s]]);export{y as __pageData,u as default};
